def compute_score() -> tuple[str, float]:
    # Open the modified presentation and get slide 3
    from pptx import Presentation
    pres = Presentation(modified_ppt_path)
    slide = pres.slides[2]
    required_text = "Ailerons control the roll movement of the aircraft"
    text_shape = None
    image_shape = None
    # Find the text box and image
    for shape in slide.shapes:
        if shape.has_text_frame and shape.text.strip().lower() == required_text.lower():
            text_shape = shape
        if shape.shape_type == 13: # PICTURE
            image_shape = shape
    if text_shape is None:
        return ("Required text box not found (shouldn't happen if previous criterion passed)", 0.0)
    if image_shape is None:
        return ("No image found on slide 3.", 0.0)
    # Check position: text box top > image bottom
    text_top = text_shape.top
    image_bottom = image_shape.top + image_shape.height
    if text_top > image_bottom:
        return ("Text box is positioned below the image.", 1.0)
    else:
        return ("Text box is NOT positioned below the image.", 0.0)

